parameters.jsCode:
const items = $input.all();

// Get data from previous nodes
const risingPages = $('Query — Rising Pages').all().map(i => i.json);
const nearPageOne = $('Query — Near Page One').all().map(i => i.json);
const lowCtr = $('Query — High Imp Low CTR').all().map(i => i.json);

const commercialKeywords = ['עולה', 'מחיר', 'כמה', 'כדאי', 'השוואה', 'פתיחת', 'איך', 'מתי', 'עלות', 'כדאיות', 'מה זה', 'הגדרה', 'קנס', 'חובה'];

const opportunities = [];

// Rising pages
risingPages.forEach(page => {
  const growth = page.impressions_prev7 > 0
    ? (page.impressions_last7 - page.impressions_prev7) / page.impressions_prev7
    : 1;
  opportunities.push({
    opportunity_type: 'rising_page',
    page_url: page.page_url,
    query: null,
    avg_position: page.avg_pos_last7,
    impressions: page.impressions_last7,
    ctr: null,
    priority_score: Math.round(page.impressions_last7 * growth * 10),
    details: JSON.stringify({ growth_pct: Math.round(growth * 100), impressions_last7: page.impressions_last7 })
  });
});

// Near page one
nearPageOne.forEach(row => {
  const closeness = 20 - row.avg_position;
  const priority = Math.round(row.total_impressions * closeness);
  const hasCommercial = commercialKeywords.some(kw => row.query.includes(kw));
  opportunities.push({
    opportunity_type: hasCommercial ? 'commercial_intent' : 'near_page_one',
    page_url: row.page_url,
    query: row.query,
    avg_position: row.avg_position,
    impressions: row.total_impressions,
    ctr: row.avg_ctr,
    priority_score: hasCommercial ? priority * 2 : priority,
    details: JSON.stringify({ closeness_to_p1: closeness })
  });
});

// High impression low CTR
lowCtr.forEach(row => {
  // Avoid duplicating near_page_one
  const alreadyAdded = opportunities.find(o => o.query === row.query && o.page_url === row.page_url);
  if (!alreadyAdded) {
    opportunities.push({
      opportunity_type: 'high_imp_low_ctr',
      page_url: row.page_url,
      query: row.query,
      avg_position: row.avg_position,
      impressions: row.total_impressions,
      ctr: row.avg_ctr,
      priority_score: Math.round(row.total_impressions * 0.5),
      details: JSON.stringify({ expected_ctr_improvement: '2-5%' })
    });
  }
});

// Sort by priority
opportunities.sort((a, b) => b.priority_score - a.priority_score);

return opportunities.map(o => ({ json: o }));

